MERGE INTO CONSULTAS FIN USING (SELECT '002845HistorialLaboralRequisitos' INFORME ,TO_CLOB(q'[SELECT ROWNUM ITEM, 
       TO_CHAR(DOCUMENTOS_PRESENTADOS.DATE_CREATED,'DD/MM/YYYY') FECHADOCUMENTO, 
           DOCUMENTOS_REQUERIDOS.NOMBRE DESCRIPCION, 
           NVL(DOCUMENTOS_PRESENTADOS.FOLIOS,' ') FOLIOS,
           SYSDATE FECHAELABORACION,
        NAT_DATOS_PERSONALES.NUMERO_DCTO CEDULA,
       NAT_DATOS_PERSONALES.APELLIDO1 || ' ' || NAT_DATOS_PERSONALES.APELLIDO2 || ' ' || NAT_DATOS_PERSONALES.NOMBRES NOMBRE_FUNCIONARIO FROM DOCUMENTOS_PRESENTADOS 
INNER JOIN DOCUMENTOS_REQUERIDOS
ON DOCUMENTOS_PRESENTADOS.COMPANIA = DOCUMENTOS_REQUERIDOS.COMPANIA
 AND DOCUMENTOS_PRESENTADOS.CODIGO = DOCUMENTOS_REQUERIDOS.CONSECUTIVO
INNER JOIN NAT_DATOS_PERSONALES
 ON DOCUMENTOS_PRESENTADOS.COMPANIA = NAT_DATOS_PERSONALES.COMPANIA
 AND DOCUMENTOS_PRESENTADOS.NUMERO_DCTO = NAT_DATOS_PERSONALES.NUMERO_DCTO
 AND DOCUMENTOS_PRESENTADOS.SUCURSAL = NAT_DATOS_PERSONALES.SUCURSAL
WHERE DOCUMENTOS_PRESENTADOS.COMPANIA = 's$compania$s'
AND DOCUMENTOS_PRESENTADOS.SUCURSAL = 's$sucursal$s' 
AND DOCUMENTOS_PRESENTADOS.NUMERO_DCTO = 's$cedulaEmpleado$s']') CONSULTA, 21 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'MPEREZ' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);